import Head from 'next/head';
import { useRouter } from 'next/router';

export async function getServerSideProps({ req }) {
  const userAgent = req.headers['user-agent'] || '';
  const posts = await fetch('https://jsonplaceholder.typicode.com/posts?_limit=5')
    .then(res => res.json());

  return {
    props: {
      posts,
      userAgent,
      timestamp: new Date().toISOString()
    }
  };
}

export default function HomePage({ posts, userAgent, timestamp }) {
  const router = useRouter();

  const navigateToBlog = () => {
    router.push('/blog');
  };

  return (
    <>
      <Head>
        <title>Home - My Blog</title>
        <meta name="description" content="Welcome to my blog homepage" />
        <meta property="og:title" content="Home - My Blog" />
      </Head>

      <div>
        <h1>Welcome to My Blog</h1>
        <p>Server-side rendered at: {timestamp}</p>
        <p>Your user agent: {userAgent}</p>

        <h2>Recent Posts</h2>
        <ul>
          {posts.map(post => (
            <li key={post.id}>
              <a href={`/blog/${post.id}`}>{post.title}</a>
            </li>
          ))}
        </ul>

        <button onClick={navigateToBlog}>
          View All Posts
        </button>
      </div>
    </>
  );
}

import Head from 'next/head';
import { useRouter } from 'next/router';

export async function getStaticProps() {
  const posts = await fetch('https://jsonplaceholder.typicode.com/posts')
    .then(res => res.json());

  return {
    props: {
      posts
    },
    revalidate: 60 // ISR with 60 second revalidation
  };
}

export default function BlogIndex({ posts }) {
  const router = useRouter();

  return (
    <>
      <Head>
        <title>Blog - My Blog</title>
        <meta name="description" content="All blog posts" />
      </Head>

      <div>
        <h1>All Blog Posts</h1>

        <div className="posts-grid">
          {posts.map(post => (
            <div key={post.id} className="post-card">
              <h2>
                <a href={`/blog/${post.id}`}>{post.title}</a>
              </h2>
              <p>{post.body.substring(0, 100)}...</p>
              <button onClick={() => router.push(`/blog/${post.id}`)}>
                Read More
              </button>
            </div>
          ))}
        </div>
      </div>
    </>
  );
}

export default function handler(req, res) {
  const { id } = req.query;

  if (req.method === 'GET') {
    // Simulate fetching a single post
    const post = {
      id: parseInt(id),
      title: `Post ${id}`,
      content: `This is the content for post ${id}`,
      createdAt: new Date().toISOString()
    };

    res.status(200).json(post);
  } else if (req.method === 'PUT') {
    const { title, content } = req.body;

    // Simulate updating a post
    const updatedPost = {
      id: parseInt(id),
      title: title || `Post ${id}`,
      content: content || `Updated content for post ${id}`,
      updatedAt: new Date().toISOString()
    };

    res.status(200).json(updatedPost);
  } else if (req.method === 'DELETE') {
    // Simulate deleting a post
    res.status(200).json({ message: `Post ${id} deleted successfully` });
  } else {
    res.setHeader('Allow', ['GET', 'PUT', 'DELETE']);
    res.status(405).end(`Method ${req.method} Not Allowed`);
  }
}

import Head from 'next/head';
import { useRouter } from 'next/router';

export async function getStaticPaths() {
  const posts = await fetch('https://jsonplaceholder.typicode.com/posts')
    .then(res => res.json());

  const paths = posts.slice(0, 10).map(post => ({
    params: { id: post.id.toString() }
  }));

  return {
    paths,
    fallback: 'blocking'
  };
}

export async function getStaticProps({ params }) {
  try {
    const [post, comments] = await Promise.all([
      fetch(`https://jsonplaceholder.typicode.com/posts/${params.id}`).then(res => res.json()),
      fetch(`https://jsonplaceholder.typicode.com/posts/${params.id}/comments`).then(res => res.json())
    ]);

    return {
      props: {
        post,
        comments
      },
      revalidate: 300 // 5 minutes
    };
  } catch (error) {
    return {
      notFound: true
    };
  }
}

export default function BlogPost({ post, comments }) {
  const router = useRouter();

  if (router.isFallback) {
    return <div>Loading...</div>;
  }

  return (
    <>
      <Head>
        <title>{post.title} - My Blog</title>
        <meta name="description" content={post.body.substring(0, 160)} />
        <meta property="og:title" content={post.title} />
        <meta property="og:description" content={post.body.substring(0, 160)} />
      </Head>

      <article>
        <button onClick={() => router.back()}>← Back</button>

        <h1>{post.title}</h1>
        <p>{post.body}</p>

        <h2>Comments ({comments.length})</h2>
        <div className="comments">
          {comments.map(comment => (
            <div key={comment.id} className="comment">
              <h3>{comment.name}</h3>
              <p>{comment.body}</p>
              <small>By: {comment.email}</small>
            </div>
          ))}
        </div>
      </article>
    </>
  );
}

import Head from 'next/head';

function Error({ statusCode, hasGetInitialPropsRun, err }) {
  return (
    <>
      <Head>
        <title>Error {statusCode}</title>
      </Head>

      <div className="error-page">
        <h1>
          {statusCode
            ? `A ${statusCode} error occurred on server`
            : 'An error occurred on client'}
        </h1>
        <p>
          {statusCode === 404
            ? 'This page could not be found.'
            : 'Sorry, something went wrong.'}
        </p>
      </div>
    </>
  );
}

Error.getInitialProps = ({ res, err }) => {
  const statusCode = res ? res.statusCode : err ? err.statusCode : 404;
  return { statusCode };
};

export default Error;

